BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?owner ?ownerName ?ownerType WHERE {
  ?elem vocab:NamedElement_name "APS%20Requirements%20Flowdown" .
  ?elem vocab:Element_owner ?owner .
  OPTIONAL { ?owner vocab:NamedElement_name ?ownerName }
  OPTIONAL { ?owner rdf:type ?ownerType }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?target ?targetName ?targetType WHERE {
  ?source vocab:NamedElement_name "Requirements%20Information%20Flow" .
  ?source vocab:Element_ownedElement ?target .
  OPTIONAL { ?target vocab:NamedElement_name ?targetName }
  OPTIONAL { ?target rdf:type ?targetType }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?flow ?flowName ?source ?sourceName ?target ?targetName WHERE {
  ?flow rdf:type <http://api.koneksys.com/cameo/vocab/item%20flow> .
  OPTIONAL { ?flow vocab:NamedElement_name ?flowName }
  OPTIONAL { ?flow <http://api.koneksys.com/cameo/vocab/InformationFlow_informationSource> ?source }
  OPTIONAL { ?source vocab:NamedElement_name ?sourceName }
  OPTIONAL { ?flow <http://api.koneksys.com/cameo/vocab/InformationFlow_informationTarget> ?target }
  OPTIONAL { ?target vocab:NamedElement_name ?targetName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
