BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?rel ?relType ?other ?otherName WHERE {
  {
    ?elem vocab:NamedElement_name "L2%20APS%20Requirements%20Document" .
    ?rel ?prop ?elem .
    ?rel rdf:type ?relType .
    ?rel ?prop2 ?other .
    FILTER(?other != ?elem)
    OPTIONAL { ?other vocab:NamedElement_name ?otherName }
  } UNION {
    ?elem vocab:NamedElement_name "L2%20APS%20Requirements%20Document" .
    ?elem ?prop ?rel .
    ?rel rdf:type ?relType .
    ?elem ?prop2 ?other .
    FILTER(?other != ?rel)
    OPTIONAL { ?other vocab:NamedElement_name ?otherName }
  }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?source ?sourceName ?target ?targetName ?prop ?value WHERE {
  {
    ?source vocab:NamedElement_name "L2%20APS%20Requirements%20Document" .
    ?source ?prop ?value .
    FILTER(CONTAINS(STR(?value), "APS%20Requirements%20Flowdown"))
  } UNION {
    ?target vocab:NamedElement_name "APS%20Requirements%20Flowdown" .
    ?target ?prop ?value .
    FILTER(CONTAINS(STR(?value), "L2%20APS%20Requirements%20Document"))
  }
  OPTIONAL { ?source vocab:NamedElement_name ?sourceName }
  OPTIONAL { ?target vocab:NamedElement_name ?targetName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
