SELECT ?source ?sourceName ?target ?targetName ?relType WHERE {
  ?source vocab:NamedElement_name "L2%20APS%20Requirements%20Document" .
  ?target vocab:NamedElement_name "APS%20Requirements%20Flowdown" .
  ?rel rdf:type ?relType .
  { ?rel <http://api.koneksys.com/cameo/vocab/InformationFlow_informationSource> ?source . ?rel <http://api.koneksys.com/cameo/vocab/InformationFlow_informationTarget> ?target } UNION
  { ?rel <http://api.koneksys.com/cameo/vocab/InformationFlow_informationSource> ?target . ?rel <http://api.koneksys.com/cameo/vocab/InformationFlow_informationTarget> ?source } UNION
  { ?rel <http://api.koneksys.com/cameo/vocab/Dependency_client> ?source . ?rel <http://api.koneksys.com/cameo/vocab/Dependency_supplier> ?target } UNION
  { ?rel <http://api.koneksys.com/cameo/vocab/Dependency_client> ?target . ?rel <http://api.koneksys.com/cameo/vocab/Dependency_supplier> ?source }
  OPTIONAL { ?source vocab:NamedElement_name ?sourceName }
  OPTIONAL { ?target vocab:NamedElement_name ?targetName }
}
LIMIT 50

